state.accessibility=state.accessibility||{};state.learnerNotes=state.learnerNotes||[];state.portfolioUploads=state.portfolioUploads||{};state.onlinePortfolioUrl=state.onlinePortfolioUrl||'';state.demoCompleted=state.demoCompleted||false;state.demoDisclaimerAccepted=state.demoDisclaimerAccepted||false;state.lastBackupReminder=state.lastBackupReminder||'';state.lastStorageWarning=state.lastStorageWarning||'';state.openPanels=state.openPanels||{};
