const course=()=>APP_COURSES.find(c=>c.id===view.courseId)||APP_COURSES[0];
function save(){state.courseId=view.courseId;state.tab=view.tab;state.apprenticeshipTab=view.apprenticeshipTab;store.set('applus-state',state)}
function key(a){return `${view.courseId}-${a.number}`}
function completedCount(c=course()){return c.assignments.filter(a=>state.completed[`${c.id}-${a.number}`]).length}
function overrideResult(id,automatic){return state.rewardOverrides[id]==='unlock'?true:state.rewardOverrides[id]==='lock'?false:automatic}
function assignmentBadgeUnlocked(c,a){const id=`${c.id}-${a.number}`,automatic=!!state.completed[id];return state.badgeOverrides[id]==='unlock'?true:state.badgeOverrides[id]==='lock'?false:automatic}
function currentXp(c=course()){const perItem=c.assignments.length===12?150:120,evidence=completedCount(c)+academyModules(c).filter(m=>state.academyPassed[m.id]).length+c.assignments.filter(a=>state.practicalAssessments[`${c.id}-PA${a.number}`]?.passed).length+c.assignments.filter(a=>state.witnessTestimonies[`${c.id}-WT${a.number}`]?.completed).length,academy=generalAcademyTests().filter(t=>state.academyTestPassed[t.id]).reduce((n,t)=>n+t.xp,0);return Math.min(10000,evidence*perItem+academy)}
function esc(s=''){return String(s).replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]))}
