function customTargetOptions(type,c=course()){if(type==='assignment')return c.assignments.filter(a=>!state.completed[`${c.id}-${a.number}`]).map(a=>({id:String(a.number),label:`AS${a.number}: ${a.title}`}));if(type==='academy')return generalAcademyTests().filter(t=>!state.academyTestPassed[t.id]).map(t=>({id:t.id,label:t.title}));if(type==='ta')return academyModules(c).filter(m=>!state.academyPassed[m.id]).map(m=>({id:m.id,label:`${m.code}: ${m.title}`}));if(type==='pa')return c.assignments.filter(a=>!state.practicalAssessments[`${c.id}-PA${a.number}`]?.passed).map(a=>({id:String(a.number),label:`PA${a.number}: ${practicalTask(c,a)}`}));if(type==='wt')return c.assignments.filter(a=>!state.witnessTestimonies[`${c.id}-WT${a.number}`]?.completed).map(a=>({id:String(a.number),label:`WT${a.number}: ${a.title}`}));return []}
