function recommendedNextAction(c=course()){
  for(const a of c.assignments){
    if(!state.completed[`${c.id}-${a.number}`])return {type:'AS',number:a.number,title:`Complete AS${a.number}: ${a.title}`,reason:'Add your written and photographic assignment evidence.',button:'Open assignment'};
    const module=academyModules(c).find(m=>m.assignmentNumber===a.number),needsTA=(a.ksbs||[]).some(x=>/^[KB]\d+/i.test(ksbCode(x)));
    const taDone=!!(module&&state.academyPassed[module.id]),paDone=!!state.practicalAssessments[`${c.id}-PA${a.number}`]?.passed,wtDone=!!state.witnessTestimonies[`${c.id}-WT${a.number}`]?.completed;
    if(!taDone&&!paDone&&!wtDone)return {type:'SUPPORT',number:a.number,module:module?.id,allowTA:needsTA&&!!module,title:`Add supporting evidence for Assignment ${a.number}`,reason:'Choose any one supporting route: Trade Academy, Practical Assessment or Witness Testimony.',button:'Choose supporting evidence'};
    if(!state.portfolioUploads[`${c.id}-${a.number}`])return {type:'UPLOAD',number:a.number,title:`Upload Assignment ${a.number} to your portfolio`,reason:'Download the completed assignment evidence, upload it to your online portfolio, then confirm completion.',button:'Prepare files'};
  }
  const academy=generalAcademyTests().find(t=>!state.academyTestPassed[t.id]);
  if(academy)return {type:'ACADEMY',test:academy.id,title:`Try ${academy.title}`,reason:`Build wider knowledge and work towards ${academy.xp} XP.`,button:'Open Academy test'};
  const revision=c.assignments.find(a=>!state.revisionProgress[`trade:${c.id}:${a.number}`]?.completed);
  if(revision)return {type:'REVISION',number:revision.number,title:`Revise AS${revision.number}: ${revision.title}`,reason:'Strengthen your course knowledge with 30 teaching slides and 10 checks.',button:'Open revision pack'};
  const mock=['knowledge','practical','interview'].find(x=>!state.epaMocks[`${c.id}-${x}`]);
  if(mock)return {type:'EPA',mock,title:`Complete the EPA ${mock==='knowledge'?'knowledge mock':mock==='practical'?'practical mock':'professional discussion'}`,reason:'Practise combining evidence and KSB knowledge under assessment-style conditions.',button:'Open EPA practice'};
  return {type:'COMPLETE',title:'Keep building professional confidence',reason:'Your recorded activities are complete. Revisit revision, practise EPA questions or update your learner notes.',button:'Open revision library'};
}
function openRecommendedAction(action){
  if(action.type==='AS'){view.tab='apprenticeship';view.apprenticeshipTab='assignments';view.assignment=action.number}
  if(action.type==='TA'){view.tab='apprenticeship';view.apprenticeshipTab='trade';view.academyModule=action.module}
  if(action.type==='PA'){view.tab='apprenticeship';view.apprenticeshipTab='practical';view.practicalAssessment=action.number}
  if(action.type==='WT'){view.tab='apprenticeship';view.apprenticeshipTab='witness';view.witnessAssignment=action.number}
  if(action.type==='UPLOAD')return;
  if(action.type==='ACADEMY'){view.tab='academy';view.academyTest=action.test}
  if(action.type==='REVISION'){view.tab='academy';view.academySection='revision';view.revisionPack=`trade:${view.courseId}:${action.number}`;view.revisionSlide=0;view.revisionAnswers={}}
  if(action.type==='EPA'){view.tab='apprenticeship';view.apprenticeshipTab='epa';view.epaMock=action.mock}
  if(action.type==='COMPLETE'){view.tab='academy';view.academySection='revision'}
  save();render();
}
