  shell('Home',`<div class="card home-progress-card"><div class="home-course"><span>COURSE PROGRESS</span><h2>${esc(c.name)}</h2></div><div class="home-progress-head"><b>${pct}%</b><span>${ksbDone} of ${rows.length} KSB's completed</span></div><div class="progress home-progress-bar"><span style="width:${pct}%"></span></div><div class="home-chart-row"><div class="evidence-pie" style="background:conic-gradient(${slices})"><div><b>${evidenceDone}</b><small>evidence</small></div></div><div class="evidence-legend">${evidence.map(x=>`<div><i style="background:${x.color}"></i><b>${x.code}</b><span>${x.done}/${x.total}</span></div>`).join('')}</div></div></div><div class="card home-rewards-card"><div class="xp-rank-row"><div><span>CURRENT XP</span><b>${xp}</b></div><div><span>CURRENT TITLE</span><strong>${rank.current.name}</strong></div></div><div class="rank-progress-copy"><b>${rank.expert?'Highest title achieved':`Next: ${rank.next.name}`}</b><span>${rank.expert?'All assignment badges collected':`${rank.remaining} badge${rank.remaining===1?'':'s'} needed`}</span></div><div class="progress rank-progress"><span style="width:${rank.progress}%"></span></div><div class="badge-heading"><b>Assignment badges</b><span>${badgesDone}/${c.assignments.length}</span></div><div class="badge-strip">${badges}</div></div><button class="card rewards-home-link" id="openRewards"><span><small>REWARDS</small><b>${pending?`${pending} ready to claim`:next?`${next.app} is your next app`:'All apps claimed'}</b><em>Apps, colour themes and agreed rewards</em></span><strong>›</strong></button><div class="card home-tools-card"><div class="home-tools-heading"><span>APPRENTICE+ TOOLS</span><h2>Your apps</h2></div><div class="home-tools-grid">${appGrid}</div></div>`);
