let updateCheckBusy=false,announcedUpdate='';
async function downloadAvailableUpdate(){
  try{
    const reg=swRegistration||await navigator.serviceWorker?.getRegistration();
    if(!reg)throw new Error('Service worker unavailable');
    toast('Downloading Apprentice+ update…');
    await reg.update();
    let worker=reg.waiting||reg.installing;
    if(worker&&worker.state!=='installed')await new Promise(resolve=>{const done=()=>{if(worker.state==='installed'){worker.removeEventListener('statechange',done);resolve()}};worker.addEventListener('statechange',done);setTimeout(resolve,12000)});
    showAppNotification({type:'updates',icon:'✓',title:'Update downloaded',message:'The new Apprentice+ version is ready. Restart now to install it.',primary:'Restart now',secondary:'Later',onPrimary:()=>{const waiting=reg.waiting||worker;if(waiting?.state==='installed'){refreshingForUpdate=true;waiting.postMessage({type:'SKIP_WAITING'});setTimeout(()=>location.reload(),1500)}else location.reload()}});
  }catch(error){toast('The update could not be downloaded. Check your connection and try again.')}
}
async function checkForAppUpdate({announce=true}={}){
  if(updateCheckBusy||!notificationEnabled('updates'))return false;
  updateCheckBusy=true;
  try{
    const response=await fetch(`version.json?t=${Date.now()}`,{cache:'no-store'});
    if(!response.ok)return false;
    const release=await response.json(),latest=String(release.version||APP_VERSION);
    latestRelease={version:latest,whatsNew:Array.isArray(release.whatsNew)?release.whatsNew:[]};
    if(latest===APP_VERSION)return false;
    if(announce&&announcedUpdate!==latest&&!$('.app-notification-wrap')){
      announcedUpdate=latest;
      showAppNotification({type:'updates',icon:'↻',title:`Build ${latest} is available`,message:'A new Apprentice+ update is ready. You can review what changed or download it now.',primary:"What's new",secondary:'Download update',onPrimary:()=>{view.tab='whatsnew';save();render()},onSecondary:downloadAvailableUpdate});
    }
    return true;
  }catch{return false}
  finally{updateCheckBusy=false}
}
