  const custom=(state.rewards||[]).find(r=>!r.claimed&&!customRewardExpired(r)&&customRewardTargetMet(r)&&!r.readyNotified);if(custom&&notificationEnabled('rewards')){custom.readyNotified=true;save();showAppNotification({type:'rewards',icon:'🎁',title:'Agreed reward ready',message:`You completed “${custom.targetLabel||custom.action}”. Your reward card for “${custom.reward}” is ready to claim.`,primary:'Open My Cards',secondary:'Later',onPrimary:()=>{view.tab='rewards';view.rewardsPage='mycards';save();render()}});return}
  const backupAge=state.lastBackupReminder?Date.now()-new Date(state.lastBackupReminder).getTime():Infinity;if(completedCount()>0&&backupAge>7*86400000){state.lastBackupReminder=new Date().toISOString();save();showAppNotification({type:'encouragement',icon:'⇩',title:'Keep your evidence safe',message:'Your Apprentice+ evidence is stored locally on this device. Export a backup regularly and upload completed work to your online portfolio.',primary:'Open Settings',secondary:'Later',onPrimary:()=>{view.tab='settings';save();render()}});return}
  showRewardNotification();if($('.app-notification-wrap'))return;
  if(!notificationEnabled('encouragement'))return;const today=new Date().toDateString();if(state.lastEncouragementDate===today)return;const c=course(),done=completedCount(c),xp=currentXp(c),next=c.assignments.find(a=>!state.completed[`${c.id}-${a.number}`]),pending=unclaimedUnlockedRewards().length,messages=pending?[`You have ${pending} reward${pending===1?'':'s'} waiting to be claimed. Open Rewards and make your progress count.`]:next?[`Your next badge is Assignment ${next.number}: ${next.title}. A little progress today moves you closer to your next title.`,`You have collected ${done} of ${c.assignments.length} assignment badges. Keep building your portfolio one task at a time.`,`You have earned ${xp.toLocaleString()} XP. Complete another course item to move towards your next reward.`]:['Every assignment badge is complete. Keep strengthening your Academy and KSB evidence.'];const message=messages[Math.floor(Date.now()/86400000)%messages.length];if(showAppNotification({type:'encouragement',icon:'＋',title:'Keep building',message,primary:'Let’s go'})){state.lastEncouragementDate=today;save()}
