function ksbCode(value=''){return String(value).match(/^[KSB]\d+/i)?.[0].toUpperCase()||String(value).trim()}
function ksbMatrix(c){
  const map=new Map();
  c.assignments.forEach(a=>(a.ksbs||[]).forEach(raw=>{
    const code=ksbCode(raw),description=String(raw).replace(/^[KSB]\d+\s*:\s*/i,'').trim();
    if(!map.has(code))map.set(code,{code,description,assignments:[]});
    if(!map.get(code).assignments.some(x=>x.number===a.number))map.get(code).assignments.push({number:a.number,title:a.title});
  }));
  const order={K:0,S:1,B:2};
  return [...map.values()].sort((a,b)=>(order[a.code[0]]-order[b.code[0]])||(Number(a.code.slice(1))-Number(b.code.slice(1))));
}
function witnessKey(number){return `${view.courseId}-WT${number}`}
function practicalSkills(a){return (a.ksbs||[]).filter(x=>ksbCode(x).startsWith('S')).map(x=>({code:ksbCode(x),description:String(x).replace(/^S\d+\s*:\s*/i,'').trim()}))}
function practicalTask(c,a){
  const brick=['Build a straight half-brick wall to the supplied dimensions.','Build a straight wall incorporating a return corner.','Build a solid one-brick wall to the supplied drawing.','Build a cavity wall with correct wall ties and insulation.','Build a wall containing a door or window opening.','Set out and build a cavity wall with a window, lintel and soldiers.','Build a wall with an attached pier and maintain the bond.','Build a wall finished with a brick-on-edge coping.','Build a wall and then accurately remove and repair five damaged bricks.','Build a decorative brickwork panel using the specified bond.','Build a cavity wall incorporating DPC, insulation and an opening.','Build a gable end with a corbel and accurate raked cuts.'];
  if(c.id==='brick')return brick[(a.number-1)%brick.length];
  const site=['Construct a small timber frame safely using the correct PPE, access equipment and controls.','Install a short run of responsibly sourced skirting to the specified standards and minimise waste.','Set out and cut a roof component accurately from the supplied drawing.','Prepare a cutting list and construct a small timber frame within the allowed material quantity.','Mark, cut and assemble a housing joint using suitable hand and power tools.','Make a repeatable cutting jig and use a laser level to install a straight run of timber battens.','Work with another carpenter to set out, assemble and check a framed opening.','Set out and construct a timber stud partition containing a framed opening.','Install floor joists, trimming and a section of sheet flooring to the supplied dimensions.','Construct a removable service pipe box and fit a section of timber cladding.','Install and align one wall unit and one base unit, including doors and ironmongery.','Set out and assemble a short stair section with a handrail and correctly spaced spindles.','Hang and adjust a timber door in a prepared lining, then fit the specified ironmongery.','Fit skirting and architrave around a prepared internal doorway with accurate mitres and scribes.','Set out, cut and assemble a small pitched-roof section containing common rafters, a ridge and ceiling joist.'];
  const bench=['Manufacture a small jointed timber frame safely using the correct PPE, extraction and controls.','Manufacture a small joinery component from responsibly sourced timber to the specified standards.','Produce a full-size setting-out rod, then mark out one component from the supplied drawing.','Prepare a cutting list and manufacture a small jointed frame within the allowed material quantity.','Mark, cut and fit a mortice-and-tenon joint using suitable hand tools and portable power tools.','Make and use a jig to produce three matching timber components accurately.','Work with another joiner to manufacture and check a small jointed frame.','Set out a door or window frame full size on a rod, including joints and section details.','Manufacture a jointed frame containing mortice-and-tenon and haunched connections.','Manufacture and fit a small opening timber casement window.','Manufacture and assemble a timber door frame with rebates, joints and a threshold detail.','Set out and manufacture a short staircase section containing strings, treads and risers.','Manufacture a framed, ledged and braced timber door to the supplied drawing.','Manufacture a small cabinet containing a carcase, door, shelf and fitted ironmongery.','Set up and use workshop machinery to produce matching planed and moulded timber sections.'];
  if(c.id==='site')return site[(a.number-1)%site.length];
  if(c.id==='bench')return bench[(a.number-1)%bench.length];
  return `Complete a practical ${a.title.toLowerCase()} task to the supplied drawing, specification and tolerances.`;
}
function practicalGenericCriteria(c,a){
  const text=`${a.title} ${practicalTask(c,a)}`.toLowerCase();
  if(/roof|rafter|gable/.test(text))return ['Safe working, access and PPE','Setting out span, pitch and centres','Rafter lengths and angle calculations','Plumb cuts and ridge fit','Birdsmouth position and fit','Level and alignment of roof members','Fixings and structural connections','Bracing and stability','Accuracy against drawing and tolerances','Finished quality and housekeeping'];
  if(/door|window|casement|lining|frame/.test(text))return ['Safe working and PPE','Setting out overall dimensions','Frame or lining square and true','Joint accuracy and fit','Rebates, grooves and profiles','Plumb, level and alignment','Clearances and consistent margins','Fixings, wedges and ironmongery','Operation and final adjustment','Finish, protection and housekeeping'];
  if(/stair|handrail|spindle|string/.test(text))return ['Safe working and PPE','Setting out total rise and going','Pitch and dimensional accuracy','String marking and cutting','Tread and riser fit','Level, plumb and alignment','Handrail height and line','Spindle spacing and secure fixing','Joints, fixings and overall stability','Finish and housekeeping'];
  if(/floor|joist/.test(text))return ['Safe working and PPE','Setting out joist centres','Joist length and bearing','Level across the floor structure','Trimming around openings','Noggins, strutting and restraint','Fixings and structural connections','Sheet layout and staggered joints','Covering fixings and finished surface','Accuracy, finish and housekeeping'];
  if(/partition|stud|cladding|pipe box|battens/.test(text))return ['Safe working and PPE','Setting out position and dimensions','Sole and head plate alignment','Stud or batten centres','Plumb, level and square','Openings, corners and junctions','Grounds, noggins and supports','Fixings and secure construction','Cladding or board fit and joints','Finish and housekeeping'];
  if(/unit|cabinet|carcase/.test(text))return ['Safe working and PPE','Setting out and component sizes','Carcase square and true','Joint accuracy and assembly','Level and plumb installation','Door and drawer alignment','Shelves, backs and internal fit','Ironmongery and fixings','Operation and final adjustment','Finish and housekeeping'];
  if(/jig|matching|machinery|moulded/.test(text))return ['Safe setup, guards, PPE and extraction','Machine or jig selection','Accurate setting and calibration','Timber preparation and orientation','First-off component check','Repeatability across components','Profile and dimensional accuracy','Surface quality and defects','Safe shutdown and storage','Finish and housekeeping'];
  return ['Safe working and correct PPE','Setting out and dimensions','Selection and preparation of materials','Tool selection and control','Accuracy and alignment','Joint preparation and fit','Square, level and plumb','Fixings and assembly','Compliance with drawing and tolerances','Finished quality and housekeeping'];
}
function practicalCriteria(c,a){
  const generic=practicalGenericCriteria(c,a);
  const skills=practicalSkills(a).slice(0,5),base=generic.slice(0,10-skills.length);
  return [...base,...skills.map(s=>`${s.code}: How well did the learner demonstrate ${s.description||'the mapped practical skill'}?`)];
}
